using BgControls.Windows.Controls;namespace BgControls.Windows.Automation.Peers;/// <summary>/// 为 <see cref="BgTabItem"/> 控件提供 UI 自动化支持的类./// </summary>public class TabItemWrapperAutomationPeer : FrameworkElementAutomationPeer{    /// <summary>    /// Initializes a new instance of the <see cref="TabItemWrapperAutomationPeer"/> class.    /// </summary>    /// <param name="owner">与此自动化节点关联的 <see cref="BgTabItem"/> 元素.</param>    public TabItemWrapperAutomationPeer(BgTabItem owner)        : base(owner)    {    }    /// <summary>    /// 获取在自动化客户端（如屏幕阅读器）中显示的类名称.    /// </summary>    /// <returns>控件的类名称字符串.</returns>    protected override string GetClassNameCore()    {        return nameof(BgTabItem);    }    /// <summary>    /// 获取此自动化节点关联控件的类型.    /// </summary>    /// <returns>表示选项卡项类型的 <see cref="AutomationControlType"/> 枚举值.</returns>    protected override AutomationControlType GetAutomationControlTypeCore()    {        return AutomationControlType.TabItem;    }}